const body = $json.body || $json;
const event = body.event || {};
const severity = String(event.severity || body.severity || '').toLowerCase();
const isCritical = severity === 'critical';
return [{ json: { accepted: isCritical, reason: isCritical ? 'critical_alert_accepted' : 'below_critical_threshold', workflow: 'HoneyPot v3 - Critical Alert Router', title: `🚨 ${body.source || 'HoneyPot v3'} critical alert`, summary: body.summary || 'HoneyPot v3 alert received', severity, source_ip: event.ip || body.ip || 'unknown', service: event.service || body.service || 'unknown', attack_category: event.attack_category || body.attack_category || 'unknown', payload: event.command || body.command || '', received_at: new Date().toISOString() } } }];
